using System.Text.Json;
using Avalonia.Threading;
using VisualRelay.App.ViewModels;
using VisualRelay.Core.Configuration;
using VisualRelay.Core.Execution;
using VisualRelay.Domain;

namespace VisualRelay.Tests;

/// <summary>
/// Tests for the "Create task to fix" button — the command that hands a flagged
/// run's failures to an LLM and creates a new llm-task in the queue.
/// </summary>
[Collection("Headless")]
public sealed class MainWindowViewModelFixTaskTests
{
    private const string AuthoredMarkdown = "# Fix flaky tests\n\nMake them deterministic.\n";
    private const string AuthoredSummary = "Fix flaky UI tests in SettingsPanel";
    private const string AuthoredSlug = "fix-flaky-tests";

    // ── Helpers ────────────────────────────────────────────────────────────

    private static MainWindowViewModel NewViewModel(TestRepository repo) =>
        new(new DictionaryEnvironmentAccessor { ["XDG_CONFIG_HOME"] = Path.Combine(repo.Root, ".xdg") })
        {
            RootPath = repo.Root,
            ShowConfirmationAsync = null,
        };

    private static TaskRowViewModel Row(MainWindowViewModel vm, string id) =>
        vm.Tasks.First(t => t.Id == id);

    /// <summary>
    /// Writes the minimum on-disk state that makes <c>HasSelectedTaskError</c>
    /// true for <paramref name="taskId"/>: a NEEDS-REVIEW flag file and a
    /// status.json with a Flagged stage entry.
    /// </summary>
    private static async Task WriteFlaggedRelayDataAsync(
        string root, string taskId, string reason = "swival timed out", int stage = 6)
    {
        var taskDirectory = Path.Combine(root, ".relay", taskId);
        Directory.CreateDirectory(taskDirectory);

        // NEEDS-REVIEW flag file — read by the RelayTaskRepository to set NeedsReview.
        await File.WriteAllTextAsync(
            Path.Combine(taskDirectory, "NEEDS-REVIEW"),
            $"{reason}\nstage {stage}\n");

        // status.json with a Flagged stage — read by LoadRunHistoryAsync to set SelectedTaskError.
        var entries = new[]
        {
            new StageStatusEntry(stage, $"Stage {stage}", "Flagged", Error: reason),
        };
        await StageStatusRecord.WriteAsync(taskDirectory, entries);
    }

    /// <summary>
    /// Returns the nested task markdown path for a slug, as written by
    /// <see cref="RelayTaskWriter.CreateAsync"/>.
    /// </summary>
    private static string NestedMarkdownPath(string root, string slug) =>
        Path.Combine(root, "llm-tasks", slug, $"{slug}.md");

    // ── CanExecute gating ──────────────────────────────────────────────────

    [AvaloniaFact]
    public async Task CanCreateFixTask_False_WhenNoFailedRun()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("clean", "# Clean\n");

        var vm = NewViewModel(repo);
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "clean");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        Assert.False(vm.HasSelectedTaskError,
            "pre-condition: task without flagged data has no error");
        Assert.False(vm.CanCreateFixTaskPublic,
            "button must be disabled when the selected task has no failed run");
    }

    [AvaloniaFact]
    public async Task CanCreateFixTask_True_WhenSelectedTaskHasFailedRun()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        var vm = NewViewModel(repo);
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        Assert.True(vm.HasSelectedTaskError,
            "pre-condition: task with flagged status.json must show an error");
        Assert.True(vm.CanCreateFixTaskPublic,
            "button must be enabled when the selected task has a failed run and nothing blocks it");
    }

    [AvaloniaFact]
    public async Task CanCreateFixTask_False_WhenIsBusy()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        var vm = NewViewModel(repo);
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        Assert.True(vm.HasSelectedTaskError);

        vm.IsBusy = true;
        Assert.False(vm.CanCreateFixTaskPublic,
            "button must be disabled when the VM is busy (e.g. a drain is running)");
        vm.IsBusy = false;
        Assert.True(vm.CanCreateFixTaskPublic,
            "button must re-enable when busy clears");
    }

    [AvaloniaFact]
    public async Task CanCreateFixTask_False_WhenAlreadyCreatingFixTask()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        var vm = NewViewModel(repo);
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        Assert.True(vm.CanCreateFixTaskPublic);

        // Simulate the in-flight creation state.
        vm.IsCreatingFixTask = true;
        Assert.False(vm.CanCreateFixTaskPublic,
            "button must be disabled while a fix task is already being created");
        vm.IsCreatingFixTask = false;
        Assert.True(vm.CanCreateFixTaskPublic);
    }

    // ── Happy path: authors markdown and writes a new task ──────────────────

    [AvaloniaFact]
    public async Task Click_AuthorsAndWritesNewTask()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        var fake = new FixTaskFakeRunner
        {
            Markdown = AuthoredMarkdown,
            Summary = AuthoredSummary,
            Slug = AuthoredSlug,
        };

        var vm = NewViewModel(repo);
        vm.FixTaskRunnerFactory = _ => fake;
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        Assert.True(vm.CanCreateFixTaskPublic);

        // Execute the command.
        await vm.CreateFixTaskCommand.ExecuteAsync(null);
        Dispatcher.UIThread.RunJobs();

        // The fake runner must have been invoked.
        Assert.True(fake.WasCalled, "the subagent runner must be invoked");

        // The new task must be written to disk.
        var expectedPath = NestedMarkdownPath(repo.Root, AuthoredSlug);
        Assert.True(File.Exists(expectedPath),
            $"fix task markdown must be written to {expectedPath}");
        Assert.Equal(AuthoredMarkdown, await File.ReadAllTextAsync(expectedPath));

        // The new task must appear in the queue.
        Assert.Contains(vm.Tasks, t => t.Id == AuthoredSlug);
    }

    // ── Slug collision disambiguation ──────────────────────────────────────

    [AvaloniaFact]
    public async Task Click_SlugCollision_Disambiguates()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        // Pre-create a task with the same slug the fake runner will suggest.
        repo.WriteNestedTask(AuthoredSlug, "# Existing\n");

        var fake = new FixTaskFakeRunner
        {
            Markdown = AuthoredMarkdown,
            Summary = AuthoredSummary,
            Slug = AuthoredSlug,
        };

        var vm = NewViewModel(repo);
        vm.FixTaskRunnerFactory = _ => fake;
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        await vm.CreateFixTaskCommand.ExecuteAsync(null);
        Dispatcher.UIThread.RunJobs();

        // The colliding slug must NOT be used.
        var collidingPath = NestedMarkdownPath(repo.Root, AuthoredSlug);
        Assert.Equal("# Existing\n", await File.ReadAllTextAsync(collidingPath),
            "the pre-existing task must be untouched");

        // A disambiguated slug must have been written (e.g. fix-flaky-tests-2).
        var disambiguatedPath = NestedMarkdownPath(repo.Root, $"{AuthoredSlug}-2");
        Assert.True(File.Exists(disambiguatedPath),
            $"disambiguated slug must be written; expected {disambiguatedPath}");

        // The new task must appear in the queue under the disambiguated id.
        Assert.Contains(vm.Tasks, t => t.Id == $"{AuthoredSlug}-2");
    }

    // ── Completion modal: "View task" selects the new task ──────────────────

    [AvaloniaFact]
    public async Task Click_CompletionModal_InvokedWithCorrectLabels()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        var fake = new FixTaskFakeRunner
        {
            Markdown = AuthoredMarkdown,
            Summary = AuthoredSummary,
            Slug = AuthoredSlug,
        };

        var confirmCalls = new List<(string Title, string Message, string ConfirmLabel)>();

        var vm = NewViewModel(repo);
        vm.FixTaskRunnerFactory = _ => fake;
        // Capture both confirmation calls and auto-confirm both.
        vm.ShowConfirmationAsync = (title, message, confirmLabel) =>
        {
            confirmCalls.Add((title, message, confirmLabel));
            return Task.FromResult(true);
        };
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        await vm.CreateFixTaskCommand.ExecuteAsync(null);
        Dispatcher.UIThread.RunJobs();

        // First confirmation: "Create task to fix" / "Create"
        Assert.Contains(confirmCalls, c =>
            c.Title == "Create task to fix" && c.ConfirmLabel == "Create");

        // Second confirmation: "Fix task created" / "View task"
        Assert.Contains(confirmCalls, c =>
            c.Title == "Fix task created" && c.ConfirmLabel == "View task");

        // The completion message must name the new task and the summary.
        var completionCall = confirmCalls.First(c => c.Title == "Fix task created");
        Assert.Contains(AuthoredSlug, completionCall.Message, StringComparison.Ordinal);
        Assert.Contains(AuthoredSummary, completionCall.Message, StringComparison.Ordinal);
    }

    [AvaloniaFact]
    public async Task Click_ViewTask_SelectsNewTask()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        var fake = new FixTaskFakeRunner
        {
            Markdown = AuthoredMarkdown,
            Summary = AuthoredSummary,
            Slug = AuthoredSlug,
        };

        var vm = NewViewModel(repo);
        vm.FixTaskRunnerFactory = _ => fake;
        // Auto-confirm both; the "View task" returns true.
        vm.ShowConfirmationAsync = (_, _, _) => Task.FromResult(true);
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        await vm.CreateFixTaskCommand.ExecuteAsync(null);
        Dispatcher.UIThread.RunJobs();

        // After completion with "View task" (true), the new task must be selected.
        Assert.NotNull(vm.SelectedTask);
        Assert.Equal(AuthoredSlug, vm.SelectedTask.Id);
    }

    [AvaloniaFact]
    public async Task Click_DismissCompletionModal_KeepsLastSelection()
    {
        // When the user dismisses the completion modal (ConfirmAsync returns false),
        // the new task must still be in the queue but the original task stays selected.
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        var fake = new FixTaskFakeRunner
        {
            Markdown = AuthoredMarkdown,
            Summary = AuthoredSummary,
            Slug = AuthoredSlug,
        };

        var vm = NewViewModel(repo);
        vm.FixTaskRunnerFactory = _ => fake;
        // First confirm (Create) → true. Second (View task) → false (dismiss).
        var callCount = 0;
        vm.ShowConfirmationAsync = (_, _, _) =>
        {
            callCount++;
            return Task.FromResult(callCount == 1); // only the first returns true
        };
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        await vm.CreateFixTaskCommand.ExecuteAsync(null);
        Dispatcher.UIThread.RunJobs();

        // The new task must exist in the queue.
        Assert.Contains(vm.Tasks, t => t.Id == AuthoredSlug);

        // The selection must still be the originally-selected (flagged) task.
        Assert.NotNull(vm.SelectedTask);
        Assert.Equal("flagged", vm.SelectedTask.Id);
    }

    // ── Error path ─────────────────────────────────────────────────────────

    [AvaloniaFact]
    public async Task Click_SubagentError_WritesNothingToDisk()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        var fake = new FixTaskFakeRunner { ThrowOnRun = true };

        var vm = NewViewModel(repo);
        vm.FixTaskRunnerFactory = _ => fake;
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        await vm.CreateFixTaskCommand.ExecuteAsync(null);
        Dispatcher.UIThread.RunJobs();

        // No task file must have been written under llm-tasks.
        var tasksDir = Path.Combine(repo.Root, "llm-tasks");
        var entries = Directory.Exists(tasksDir)
            ? Directory.GetFileSystemEntries(tasksDir)
            : [];
        // The only entry should be the pre-existing "flagged" task.
        Assert.Single(entries);
        Assert.Contains("flagged", Path.GetFileName(entries[0]), StringComparison.Ordinal);

        // The error must be surfaced in StatusText.
        Assert.Contains("Couldn't create fix task", vm.StatusText, StringComparison.OrdinalIgnoreCase);

        // The button must be re-enabled for retry.
        Assert.False(vm.IsCreatingFixTask);
    }

    [AvaloniaFact]
    public async Task Click_SubagentError_SurfacesMessageAndReEnablesButton()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        var fake = new FixTaskFakeRunner { ThrowOnRun = true };

        var vm = NewViewModel(repo);
        vm.FixTaskRunnerFactory = _ => fake;
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        await vm.CreateFixTaskCommand.ExecuteAsync(null);
        Dispatcher.UIThread.RunJobs();

        Assert.Contains("Couldn't create fix task", vm.StatusText, StringComparison.OrdinalIgnoreCase);
        Assert.False(vm.IsCreatingFixTask, "button must leave the creating state on error");
        Assert.Equal("Create task to fix", vm.CreateFixTaskButtonLabel);
    }

    // ── Headless: ConfirmAsync auto-resolves ───────────────────────────────

    [AvaloniaFact]
    public async Task Click_Headless_AutoResolvesConfirmAsync()
    {
        // With ShowConfirmationAsync == null (headless), ConfirmAsync returns
        // true automatically, so the full flow completes without hanging.
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        var fake = new FixTaskFakeRunner
        {
            Markdown = AuthoredMarkdown,
            Summary = AuthoredSummary,
            Slug = AuthoredSlug,
        };

        var vm = NewViewModel(repo); // ShowConfirmationAsync = null
        vm.FixTaskRunnerFactory = _ => fake;
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        // Must not throw or hang — headless auto-resolves both confirmations.
        await vm.CreateFixTaskCommand.ExecuteAsync(null);
        Dispatcher.UIThread.RunJobs();

        Assert.True(File.Exists(NestedMarkdownPath(repo.Root, AuthoredSlug)));
        Assert.False(vm.IsCreatingFixTask);
    }

    // ── Busy state during creation ─────────────────────────────────────────

    [AvaloniaFact]
    public async Task Click_SetsIsCreatingFixTask_DuringExecution()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteNestedTask("flagged", "# Flagged\n");
        await WriteFlaggedRelayDataAsync(repo.Root, "flagged");

        // Use a gate so the runner parks — we can observe the in-flight state.
        var gate = new TaskCompletionSource();
        var fake = new GatedFixTaskRunner(AuthoredMarkdown, AuthoredSummary, AuthoredSlug, gate.Task);

        var vm = NewViewModel(repo);
        vm.FixTaskRunnerFactory = _ => fake;
        await vm.LoadInitialAsync();
        vm.SelectedTask = Row(vm, "flagged");
        await (vm.LastSelectionLoad ?? Task.CompletedTask);

        // Start the fix-task creation; it parks inside the runner.
        vm.CreateFixTaskCommand.Execute(null);
        Dispatcher.UIThread.RunJobs();

        Assert.True(vm.IsCreatingFixTask, "IsCreatingFixTask must be true while the runner is working");
        Assert.Equal("Creating fix task…", vm.CreateFixTaskButtonLabel);
        Assert.False(vm.CanCreateFixTaskPublic,
            "button must be disabled while a fix task is being created");

        // Release the runner and let completion land.
        gate.SetResult();
        // Pump the dispatcher to let the UI-thread continuation run.
        Dispatcher.UIThread.RunJobs();
        // Pump a few more times for async continuations.
        for (var i = 0; i < 10; i++)
        {
            Dispatcher.UIThread.RunJobs();
            await Task.Delay(10);
        }

        Assert.False(vm.IsCreatingFixTask, "IsCreatingFixTask must be false after completion");
        Assert.Equal("Create task to fix", vm.CreateFixTaskButtonLabel);
    }
}

// ── Fake runners ───────────────────────────────────────────────────────────

/// <summary>
/// A fake <see cref="ISubagentRunner"/> for the fix-task-author path.
/// Returns a JSON payload with markdown, summary, and slug so the
/// <c>FixTaskAuthorRunner</c> can parse it.
/// </summary>
internal sealed class FixTaskFakeRunner : ISubagentRunner
{
    public string Markdown { get; init; } = "# Fix\n\nMake it work.\n";
    public string Summary { get; init; } = "Fix the issue";
    public string Slug { get; init; } = "fix-issue";
    public bool ThrowOnRun { get; init; }
    public bool WasCalled { get; private set; }

    public Task<SubagentResult> RunAsync(StageInvocation invocation, CancellationToken ct)
    {
        WasCalled = true;

        if (ThrowOnRun)
            throw new InvalidOperationException("synthetic fix-task-author failure");

        ct.ThrowIfCancellationRequested();

        var payload = new Dictionary<string, string>
        {
            ["markdown"] = Markdown,
            ["summary"] = Summary,
            ["slug"] = Slug,
        };
        var json = JsonSerializer.Serialize(payload);

        return Task.FromResult(new SubagentResult(
            RawText: $"```json\n{json}\n```",
            Json: json,
            IsValid: true,
            Error: null));
    }
}

/// <summary>
/// Parks inside <see cref="RunAsync"/> until an external gate completes, then
/// returns the authored payload — letting a view-model test observe the
/// in-flight <c>IsCreatingFixTask</c> state deterministically.
/// </summary>
internal sealed class GatedFixTaskRunner : ISubagentRunner
{
    private readonly string _markdown;
    private readonly string _summary;
    private readonly string _slug;
    private readonly Task _gate;

    public GatedFixTaskRunner(string markdown, string summary, string slug, Task gate)
    {
        _markdown = markdown;
        _summary = summary;
        _slug = slug;
        _gate = gate;
    }

    public async Task<SubagentResult> RunAsync(StageInvocation invocation, CancellationToken ct)
    {
        await _gate.WaitAsync(ct);

        var payload = new Dictionary<string, string>
        {
            ["markdown"] = _markdown,
            ["summary"] = _summary,
            ["slug"] = _slug,
        };
        var json = JsonSerializer.Serialize(payload);

        return new SubagentResult(
            RawText: $"```json\n{json}\n```",
            Json: json,
            IsValid: true,
            Error: null);
    }
}

